parameters.jsCode:
// Pull the JSON object out of Claude's text response and forward it.
const msg = $input.first().json;
const raw = msg?.content?.[0]?.text ?? '';

// Strip ```json fences if the model added them despite instructions.
const cleaned = raw
  .trim()
  .replace(/^```(?:json)?\s*/i, '')
  .replace(/```$/i, '')
  .trim();

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  parsed = {
    species: null,
    common_name: null,
    confidence: 0,
    care_notes: null,
    growth: { height_cm: null, leaf_count: null },
    _parse_error: e.message,
    _raw: raw,
  };
}
return [{ json: parsed }];
